sinks.expression:
printf(
						/* translators: 1: composer command. 2: plugin directory */
						esc_html__( 'Your installation of the Pinterest for WooCommerce plugin is incomplete. Please run %1$s within the %2$s directory.', 'pinterest-for-woocommerce' ),
						'<code>composer install</code>',
						'<code>' . esc_html( str_replace( ABSPATH, '', __DIR__ ) ) . '</code>'
					)

array_filter(
			$locations,
			function ( $location ) use ( $allowed_countries ) {
				return in_array( $location['country'], $allowed_countries, true );
			}
		)

array_filter(
			GoogleProductTaxonomy::TAXONOMY,
			function( $category ) use ( $search_text ) {
				return isset( $category['label'] ) && false !== stripos( $category['label'], $search_text );
			}
		)

array_filter(
			$this->trackers,
			function ( $item ) use ( $tracker ) {
				if ( get_class( $item ) === $tracker ) {
					$item->disable_hooks();
					return false;
				}
				return true;
			}
		)

